    blockDim = 8;
    singleCoreM = (M + blockDim - 1) / blockDim;
  } else if (N > 8 * M) {
    blockDim = 8;
    singleCoreN = (N + blockDim - 1) / blockDim;
  } else {
    // Balanced: split both dimensions as needed.
    blockDim = 8;
    singleCoreM = (M + blockDim - 1) / blockDim;
    singleCoreN = 1;
